boot.artifact:
// inferred-not-tested:固定 CSS 明确落 artifact document.head,并关闭上游自动注入
import GUI from 'https://cdn.jsdelivr.net/npm/lil-gui@0/+esm';
const css = Object.assign(document.createElement('link'), { rel:'stylesheet', href:'https://cdn.jsdelivr.net/npm/lil-gui@0.21.0/dist/lil-gui.css' }); document.head.appendChild(css);
const gui = new GUI({ container: document.getElementById('gui'), title: data.title ?? 'Controls', injectStyles: false });
for (const d of data.controllers) { const c = d.options ? gui.add(data.params, d.key, d.options) : gui.add(data.params, d.key, d.min, d.max, d.step); if (d.label) c.name(d.label); }
if (data.closed ?? false) gui.close();

boot.widget:
// CSS 必须进 shadow(铁律 2);injectStyles:false 阻止 lil-gui 写 document.head
import GUI from 'https://cdn.jsdelivr.net/npm/lil-gui@0/+esm';
const css = Object.assign(document.createElement('link'), { rel:'stylesheet', href:'https://cdn.jsdelivr.net/npm/lil-gui@0.21.0/dist/lil-gui.css' }); shadowRoot.appendChild(css);
const el = document.createElement('div'); shadowRoot.appendChild(el);
const gui = new GUI({ container: el, title: data.title ?? 'Controls', injectStyles: false });
for (const d of data.controllers) { const c = d.options ? gui.add(data.params, d.key, d.options) : gui.add(data.params, d.key, d.min, d.max, d.step); if (d.label) c.name(d.label); }
if (data.closed ?? false) gui.close();
